package com.shecancode.order.model; import jakarta.persistence.*; import java.math.BigDecimal; @Entity public class CartItem { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private Long cartId; private Long productId; private String productName; private BigDecimal unitPrice; private int quantity; private BigDecimal subtotal; public Long getId(){return id;} public Long getCartId(){return cartId;} public void setCartId(Long v){cartId=v;} public Long getProductId(){return productId;} public void setProductId(Long v){productId=v;} public String getProductName(){return productName;} public void setProductName(String v){productName=v;} public BigDecimal getUnitPrice(){return unitPrice;} public void setUnitPrice(BigDecimal v){unitPrice=v;} public int getQuantity(){return quantity;} public void setQuantity(int v){quantity=v;} public BigDecimal getSubtotal(){return subtotal;} public void setSubtotal(BigDecimal v){subtotal=v;} }